function autoFormatTime(R){let u=R['value']['replace'](/\D/g,'');switch(u['length']>0x4&&(u=u['slice'](0x0,0x4)),u['length']){case 0x0:case 0x1:case 0x2:R['value']=u;break;case 0x3:if(parseInt(u['slice'](0x0,0x2),0xa)<=0x17)R['value']=u['slice'](0x0,0x2)+':'+u['slice'](0x2);else{let s=u['slice'](0x0,0x1)['padStart'](0x2,'0'),F=u['slice'](0x1);R['value']=s+':'+F;}break;case 0x4:let c=u['slice'](0x0,0x2),v=u['slice'](0x2);R['value']=c+':'+v;}}function transformTimeValue(R){let u=R['trim']();if(/^\d{2}$/['test'](u))return u[0x0]['padStart'](0x2,'0')+':'+u[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](u))return 0x3===u['length']?parseInt(u['slice'](0x0,0x2),0xa)<=0x17?u['slice'](0x0,0x2)+':'+u['slice'](0x2):u['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+u['slice'](0x1):u['slice'](0x0,0x2)+':'+u['slice'](0x2);if(u['includes'](':')){let [c,v]=u['split'](':');return v||(v='00'),c=c['padStart'](0x2,'0'),v=v['padStart'](0x2,'0'),c+':'+v;}return u;}